root.script:
  function getRandomInt(max) {
    return Math.floor(Math.random() * Math.floor(max));
  }
	if ($.Language() !== "schinese") {
    $("#qq_groups").style.visibility = "collapse";
    $("#GameplayTooltipPanel").style.visibility = "collapse";
  }else{
    $("#discord").style.visibility = "collapse";
    $("#gameplay_tooltip").text = $.Localize("#game_tooltip_" + (getRandomInt(20) + 1));
  }
